import unittest # импортируем библиотеку для написания тестов на Python
from unittest.mock import patch, MagicMock # импортирует инструменты для подмены объектов во время исполнения тестов, patch временно заменяет функцию на мок, MagicMock создает заглушку, где можно настраивать значения
import requests # импортируем библиотеку request, необходимую для отправки HTTP-запросов
import telebot # импортируем библиотеку telebot, необходимую для работы с ботом Телеграмма

class TestWeatherBot(unittest.TestCase): # объявляем класс TestWeatherBot, который наследуется от unitest.TestCase, все методы класса запускаются как отдельный тест
    
    @patch('requests.get') # @patch временно заменяет получаемое значение GET на мок-объект
    def test_get_weather_success(self, mock_get): # объявляем функцию test_get_weather_success, где мы будем тестировать успешный запрос погоды, в mock_get мы указываем необходимый ответ
        mock_response = MagicMock() # присваеваем переменной mock_response мок-значения для имитации ответа от сервера
        mock_response.status_code = 200 # присваеваем атрибуту status_code значение 200, что означает успешный ответ сервера
        mock_response.json.return_value = { # прописываем json-словарь, который функция получит в ответ при вызове метода .json()
            'name': 'Moscow', # указываем название города в ответе
            'main': {'temp': 22.5, 'feels_like': 20.1, 'humidity': 60}, # указываем температуру, ощущаемую температуру и влажность
            'weather': [{'description': 'clear sky'}], # указываем описание погоды в виде списка со словарем
            'wind': {'speed': 4.5} # указываем скорость ветра
        }
        mock_get.return_value = mock_response # объявляем, что при вызове requests.get, она получит ответ с необходимыми нам данными, содержащимися в переменной mock_response
        
        # эмулируем функцию get_weather, которая принимает API-ключ, соответственно
        def fake_get_weather(openweather_api): # объявляем фукнцию, возвращающая данные о погоде, которая принимает API-ключ, соответственно
            url = f"https://api.openweathermap.org/data/2.5/weather?q=Moscow,RU&appid={openweather_api}&units=metric&lang=ru" # указываем f-строку, там формируем URL для запроса, где указываем протокол HTTP; доменное имя, заканчивающееся на \; раздел data, заканчивающееся на \; подраздел на 2.5, заканчивающееся на \; под-подраздел weather, заканчивающееся на \; параметр запроса с городом и кодом страны, заканчивающееся на &; параметр запроса, где указываем API-ключ, заканчивающееся на &; параметр запроса, где указываем, что хотим получить ответ в метрах, заканчивающееся на &; параметр запроса, где указываем, что хотим получить ответ на русском языке, заканчивающееся на &
            try: # пробуем произвести действия
                response = requests.get(url) # отправляем GET-запрос к API, для чего присваем переменной значения запроса GET на переменную «url», при этом используется замоканный requests.get
                
                if response.status_code == 200: # проверяем код ответа сервера, если ответ – «200», действем следующим образом:
                    data = response.json() # расшифровываем JSON-ответ для Python, для чего присваиваем переменой текст из полученного в ответ файла .json
                    
                    # извлекаем данные
                    city = data['name'] # приваеваем переменной значение словаря (неупорядоченная коллекция пар «ключ‑значение») name, находящегося в уже расшифрованном json-файле
                    temp = data['main']['temp'] # присваеваем переменной значение ключа temp, принадлежавшего словарю main, находящегося в уже расшифрованном json-файле
                    feels_like = data['main']['feels_like'] # присваеваем переменной значение ключа feels_like, принадлежавшего словарю main, находящегося в уже расшифрованном json-файле
                    description = data['weather'][0]['description'] # присваеваем переменной значение ключа description, принадлежавшего первому элементу списка weather, находящегося в уже расшифрованном json-файле
                    humidity = data['main']['humidity'] # присваеваем переменной значение ключа humidity, принадлежавшего словарю main, находящегося в уже расшифрованном json-файле
                    wind_speed = data['wind']['speed'] # присваеваем переменной значение ключа speed, принадлежавшего словарю wind, находящегося в уже расшифрованном json-файле
                    
                    # переменная принимает результат запроса
                    result = ( # присваеваем переменной result результат запроса
                        f"--- Погода в городе {city} ---\n\n" # с помощью f-строки выводим погоду в городе, указанном в переменной city
                        f"Температура:      {temp}°C\n" # с помощью f-строки выводим температуру, указанном в переменной temp
                        f"Ощущается как:    {feels_like}°C\n" # с помощью f-строки выводим ощущаемую температуру, указанном в переменной feels_like
                        f"Состояние неба:   {description.capitalize()}\n" # с помощью f-строки выводим состояние неба, указанное в переменной description, при этом метод .capitalize() преобразует первую букву строки в заглавную, а остальные — в строчные
                        f"Влажность:        {humidity}%\n" # с помощью f-строки выводим влажность, указзаную в переменной humidity
                        f"Скорость ветра:   {wind_speed} м/с" # с помощью f-строки выводим скорость ветра, указанную в переменной wind_speed
                    )
                    
                    return result # возвращаем результат запроса для дальнейшего отображения
                
                elif response.status_code == 401: # проверяем код ответа сервера, если ответ – «401», действем следующим образом:
                    print("\nОшибка 401: Неверный API ключ. Проверьте правильность ввода.") # выводим сообщение об ошибке 401 и его значении
                elif response.status_code == 404: # проверяем код ответа сервера, если ответ – «404», действем следующим образом:
                    print("\nОшибка 404: Город не найден.") # выводим сообщение об ошибке 404 и его значении
                else: # проверяем код ответа сервера, если ответ отличается от вышепрописанных, действуем следующим образом:
                    print(f"\nПроизошла ошибка при запросе. Код ответа: {response.status_code}") # выводим сообщение об ошибке, выводим код ошибки, которое получим в ответ на зпрос
            # если какое-то из действий, кроме print, приводит к ошибке, переходим к следующему шагу. если ошибка возникнет при запуске print, Python прекратит инициализацию кода досрочно
            except requests.exceptions.RequestException as e: # если при выполнии функции try возникла ошибка, тогда выполняется блок кода для обработки исключений, инициализируемый функцией except, запускается базовый класс исключений для ошибок, связанных с HTTP‑запросами через библиотеку requests (например, проблемы с подключением, таймауты, ошибки сервера и т. п.), далее присваивает значение перехваченного исключения переменной e
                print(f"\nОшибка сети или подключения: {e}") # с помощью f-строки выводим сообщение об ошибки, код ошибки указываем из значения переменной e
        
        result = fake_get_weather('fake_api_key') # присваеваем переменной result результат вызова эмулированной функции get_weather, передавая ей фиктивный API-ключ
        self.assertIsNotNone(result) # проверяем, что функция вернула не None, то есть результат успешно получен
        self.assertIn('Moscow', result) # проверяем, что в ответе есть название города 'Moscow'
        self.assertIn('22.5°C', result) # проверяем, что в ответе есть температура '22.5°C'
        self.assertIn('Clear sky', result) # проверяем, что в ответе есть описание погоды 'Clear sky'
        self.assertIn('Скорость ветра:', result) # проверяем, что в ответе есть строка 'Скорость ветра:'
    
    @patch('requests.get') # @patch временно заменяет получаемое значение GET на мок-объект
    def test_get_weather_network_exception(self, mock_get): # объявляем функцию test_get_weather_network_exception, где мы будем тестировать ошибку сети, в mock_get мы указываем необходимый ответ
        mock_get.side_effect = requests.exceptions.ConnectionError('No internet') # вызываем из библиотеки request, с помощью свойства .side_effect, ошибку requests.exceptions.ConnectionError, т.е. ошибку подключения интернета и присваиваем это значение переменной mock_get
        
        # эмулируем функцию get_weather, которая принимает API-ключ, соответственно
        def fake_get_weather(openweather_api): # объявляем фукнцию, возвращающая данные о погоде, которая принимает API-ключ, соответственно
            url = f"https://api.openweathermap.org/data/2.5/weather?q=Moscow,RU&appid={openweather_api}&units=metric&lang=ru" # указываем f-строку, там формируем URL для запроса
            try: # пробуем произвести действия
                response = requests.get(url) # отправляем GET-запрос к API, для чего присваем переменной значения запроса GET на переменную «url», при этом используется замоканный requests.get, который вызовет ошибку
            except requests.exceptions.RequestException as e: # если при выполнии функции try возникла ошибка, тогда выполняется блок кода для обработки исключений
                print(f"\nОшибка сети или подключения: {e}") # с помощью f-строки выводим сообщение об ошибки, код ошибки указываем из значения переменной e
                return None # возвращаем None, так как произошла ошибка
        
        result = fake_get_weather('fake_api_key') # присваеваем переменной result результат вызова эмулированной функции get_weather, передавая ей фиктивный API-ключ
        self.assertIsNone(result) # проверяем, что функция вернула None, что означает ошибку
    
    def test_bot_keyboard(self): # объявляем функцию test_bot_keyboard, которая проверяет создание кнопки
        def bot_keyboard(): # объявляем фукнцию, возвращающая кнопки под полем ввода (Reply-клавиатуру)
            markup = telebot.types.ReplyKeyboardMarkup(resize_keyboard=True) # присваемваем переменной markup объект типа ReplyKeyboardMarkup. параметр resize_keyboard=True говорит, что нужно автоматически подогнать размер кнопок под ширину текста
            markup.add(telebot.types.KeyboardButton('Какая погода сейчас в Москве?')) # с помощью метода .add() добалвется кнопка с текстом «Какая погода сейчас в Москве?», при нажатии которой боту отправляется указанный текст
            return markup # функция возвращает готовый объект
        
        markup = bot_keyboard() # присваеваем переменной markup результат вызова функции bot_keyboard
        self.assertIsInstance(markup, telebot.types.ReplyKeyboardMarkup) # проверяем, что переменная markup является экземпляром класса ReplyKeyboardMarkup библиотеки telebot
        self.assertTrue(markup.resize_keyboard) # проверяем, что атрибут resize_keyboard равен True
        
        button = markup.keyboard[0][0] # получаем саму кнопку, обращаясь к первому ряду и первой кнопке в нем
        
        # проверяем тип кнопки: в некоторых версиях telebot это словарь, в других - объект KeyboardButton
        if isinstance(button, dict): # проверяем, является ли кнопка словарем
            self.assertEqual(button['text'], 'Какая погода сейчас в Москве?') # если это словарь, обращаемся по ключу 'text' и проверяем соответствие текста
        else: # если кнопка не является словарем
            self.assertEqual(button.text, 'Какая погода сейчас в Москве?') # если это объект, обращаемся к атрибуту .text и проверяем соответствие текста
    
    @patch('telebot.TeleBot') # @patch временно заменяет конструктор TeleBot на мок-объект, чтобы не создавать реального бота
    def test_start_message(self, mock_bot): # объявляем функцию test_start_message, где мы будем тестировать команду /start, в mock_bot мы указываем мок-объект для бота
        bot_instance = MagicMock() # создаем мок-экземпляр бота с помощью MagicMock
        mock_bot.return_value = bot_instance # присваиваем, что при вызове TeleBot() будет возвращен наш мок-экземпляр
        
        # эмулируем функцию start_message, которая принимает сообщение пользователя
        def start_message(message): # объявляем функцию, которая принимает сообщение пользователя
            markup = telebot.types.ReplyKeyboardMarkup(resize_keyboard=True) # присваемваем переменной markup объект типа ReplyKeyboardMarkup. параметр resize_keyboard=True говорит, что нужно автоматически подогнать размер кнопок под ширину текста
            markup.add(telebot.types.KeyboardButton('Какая погода сейчас в Москве?')) # с помощью метода .add() добалвется кнопка с текстом «Какая погода сейчас в Москве?», при нажатии которой боту отправляется указанный текст
            bot_instance.send_message( # отправляем сообщение в чат пользователя по следующим параметрам, используя мок-экземпляр бота:
                message.chat.id, # уникальный индификатор чата, откуда пришло сообщение
                "Нажми на кнопку, чтобы узнать погоду.", # текст сообщения, соответственно
                reply_markup=markup # под сообщением появляется кнопка, которую возвращает функция bot_keyboard()
            )
        
        mock_message = MagicMock() # присваеваем переменной mock_message мок-значения для имитации сообщения
        mock_message.chat.id = 123456789 # присваеваем переменной mock_message значения индификатора чата, куда ответит бот
        
        start_message(mock_message) # вызываем эмулированную функцию start_message с мок-сообщением
        
        bot_instance.send_message.assert_called_once() # проверяем, что метод send_message был вызван только один раз
        args, kwargs = bot_instance.send_message.call_args # присваиваем args значение кортежа с идентификатором чата и текстом, отправляемым после выполнения команды /start; kwargs значение аргумента reply_markup
        self.assertEqual(args[0], 123456789) # проверяем, что идентификатор чата равен '123456789'
        self.assertIn('Нажми на кнопку', args[1]) # проверяем, что текст, отправляемый после выполнения команды /start, содержит 'Нажми на кнопку'
        self.assertIn('reply_markup', kwargs) # проверяем, что в kwargs есть ключ 'reply_markup'
    
    @patch('telebot.TeleBot') # @patch временно заменяет конструктор TeleBot на мок-объект, чтобы не создавать реального бота
    def test_handle_message_weather_button_success(self, mock_bot): # объявляем функцию test_handle_message_weather_button_success, где мы будем тестировать успешное нажатие кнопки, в mock_bot мы указываем мок-объект для бота
        bot_instance = MagicMock() # создаем мок-экземпляр бота с помощью MagicMock
        mock_bot.return_value = bot_instance # присваиваем, что при вызове TeleBot() будет возвращен наш мок-экземпляр
        
        # создаем мок для функции get_weather, которая возвращает тестовые данные
        def mock_get_weather(api_key): # объявляем функцию-заглушку, которая имитирует получение погоды
            return "Погода: +20°C" # возвращаем тестовую строку с погодой
        
        # эмулируем функцию handle_weather_button, которая принимает сообщение пользователя
        def handle_weather_button(message): # объявляем функцию, которая принимает сообщение пользователя
            if message.text == "Какая погода сейчас в Москве?": # если текст сообщения соответствует "Какая погода сейчас в Москве?", выполнияем следующие действия:
                weather_result = mock_get_weather('fake_api_key') # присваеваем переменной weather_result результат вызова мок-функции get_weather, передавая ей фиктивный API-ключ
                bot_instance.send_message( # отправляем сообщение в чат пользователя по следующим параметрам, используя мок-экземпляр бота:
                    message.chat.id, # уникальный индификатор чата, откуда пришло сообщение
                    weather_result # текст, который содержится в переменной weather_result
                )
        
        mock_message = MagicMock() # присваеваем переменной mock_message мок-значения для имитации сообщения
        mock_message.text = "Какая погода сейчас в Москве?" # присваеваем переменной mock_message текст "Какая погода сейчас в Москве?"
        mock_message.chat.id = 987654321 # присваеваем переменной mock_message значения индификатора чата
        
        handle_weather_button(mock_message) # вызываем эмулированную функцию handle_weather_button с мок-сообщением
        
        bot_instance.send_message.assert_called_once() # проверяем, что метод send_message был вызван только один раз
        args, _ = bot_instance.send_message.call_args # присваеваем args значение кортежа с идентификатором чата и текстом, отправляемым после нажатия кнопки
        self.assertEqual(args[1], "Погода: +20°C") # проверяем, что в ответ мы получили текст "Погода: +20°C"
    
    @patch('telebot.TeleBot') # @patch временно заменяет конструктор TeleBot на мок-объект, чтобы не создавать реального бота
    def test_handle_message_wrong_text(self, mock_bot): # объявляем функцию test_handle_message_wrong_text, где мы будем тестировать обработку неправильного текста, в mock_bot мы указываем мок-объект для бота
        bot_instance = MagicMock() # создаем мок-экземпляр бота с помощью MagicMock
        mock_bot.return_value = bot_instance # присваиваем, что при вызове TeleBot() будет возвращен наш мок-экземпляр
        
        # эмулируем функцию handle_weather_button, которая принимает сообщение пользователя
        def handle_weather_button(message): # объявляем функцию, которая принимает сообщение пользователя
            if message.text == "Какая погода сейчас в Москве?": # если текст сообщения соответствует "Какая погода сейчас в Москве?", выполнияем следующие действия:
                # Не должно выполниться, так как текст не соответствует
                bot_instance.send_message(message.chat.id, "Test") # отправляем тестовое сообщение (эта строка не должна выполниться)
        
        mock_message = MagicMock() # присваеваем переменной mock_message мок-значения для имитации сообщения
        mock_message.text = "Привет, как дела?" # присваеваем переменной mock_message значение "Привет, как дела?", которое не соответствует ожидаемому
        mock_message.chat.id = 111111111 # присваеваем переменной mock_message значения индификатора чата
        
        handle_weather_button(mock_message) # вызываем эмулированную функцию handle_weather_button с мок-сообщением
        
        bot_instance.send_message.assert_not_called() # проверяем, что метод send_message НЕ был вызван, так как текст не соответствует условию

if __name__ == '__main__': # проверяем, запущен ли файл напрямую, а не импортирован как модуль
    unittest.main() # стандартный блок, указывающий, если этот файл запущен напрямую, нужно найти все методы, начинающиеся с test_, и запустить их через unittest